#include <bits/stdc++.h>
using namespace std;
int n,a[10];
bool use[10];
void dfs(int x){
    if(x>n){
        for(int i=1;i<=n;i++)
            cout<<setw(5)<<a[i];
        printf("\n");
    }
    for(int i=1;i<=n;i++)
        if(!use[i])
            use[i]=1,a[x]=i,dfs(x+1),use[i]=0;
}
int main(){
    scanf("%d",&n);
    dfs(1);
    return 0;
}
